mapper.select:
select id, seller_id, category, name, description, price, wechat, address, status, create_time, update_time from product where status = '已上架' and id in
#{id}
order by create_time desc, id desc

mapper.update:
update product
set category = #{category},
    name = #{name},
    description = #{description},
    price = #{price},
    wechat = #{wechat},
    address = #{address},
    status = #{status}
where id = #{id}
  and seller_id = #{sellerId}
